package com.qilang.test.kyc;

import lombok.extern.slf4j.Slf4j;

@Slf4j
public class GetDecode {

    public GetDecode() {
    }

    public static String getSm2(String str, String key) {
        try {
            String data = SM2Utils.decryptByVK1(key, str);
            return data != null && !StringUtil.isMessyCode(data) ? data : null;
        } catch (Exception e) {
            log.error("解密sm2失败", e);
            return String.format("%s: %s", "解密sm2失败", str);
        }
    }


    public static void main(String[] args) {
        System.out.println(getSm2("", "FFCC6916A7E1A7C6D4CEF75EDF982989BBB791EAB6CA6547AA8B47AAACEED00B"));
    }
}
